import java.util.*;class A{public static void main(String[]a){var s=new Scanner(System.in);int n=s.nextInt();int[][]t=new int[n][2];for(int i=0;i<n;i++){int j=s.nextInt(),d=s.nextInt();t[i]=new int[]{j+d-1,j};}Arrays.sort(t,(x,y)->x[0]-y[0]);int c=0,e=-1;for(var v:t)if(v[1]>e){c++;e=v[0];}System.out.println(c);}}